import React, { useState } from 'react';

const App = () => {
  const [categories, setCategories] = useState([]);
  const [newCategory, setNewCategory] = useState('');
  const [filter, setFilter] = useState('');

  const addCategory = () => {
    setCategories([...categories, newCategory]);
    setNewCategory('');
  };

  const filterCategories = () => {
    const filteredCategories = categories.filter(category => category.includes(filter));
    return filteredCategories;
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#C06C88] p-4 rounded-lg">
        <h1 className="text-2xl font-bold mb-4">Categories</h1>
        <input
          type='text'
          value={newCategory}
          onChange={(e) => setNewCategory(e.target.value)}
          placeholder='New Category'
          className='w-full p-2 mb-2 text-sm text-white bg-transparent border-b border-gray-600'
        />
        <button
className='bg-[#B7D7CD] p-2 text-sm text-white hover:bg-[#411C56]' onClick={addCategory}>Add</button>
        <ul className='list-none mb-4 flex flex-wrap gap-4'>
          {categories.map((category, index) => (
            <li key={index}
className='bg-[#C06C88] p-2 text-sm text-white rounded-lg hover:bg-[#411C56]'>{category}</li>
          ))}
        </ul>
        <input
          type='text'
          value={filter}
          onChange={(e) => setFilter(e.target.value)}
          placeholder='Filter Categories'
          className='w-full p-2 mb-2 text-sm text-white bg-transparent border-b border-gray-600'
        />
        <ul className='list-none mb-4 flex flex-wrap gap-4'>
          {filterCategories().map((category, index) => (
            <li key={index}
className='bg-[#C06C88] p-2 text-sm text-white rounded-lg hover:bg-[#411C56]'>{category}</li>
          ))}
        </ul>
      </div>
    </div>
  );
};

export default App;
